mapper.select:


    m.status = '0'

        and m.message_type = #{bizMessage.messageType}


        and m.message_title like concat('%', #{bizMessage.messageTitle}, '%')


        and case when r.read_id is null then '0' else '1' end = #{bizMessage.readStatus}


order by m.message_id desc

select m.message_id, m.message_type, m.message_title, m.message_content, m.message_level, m.business_type, m.business_id, m.status,
       m.create_by, m.create_time, m.update_by, m.update_time, m.remark,
       '0' as read_status
from biz_message m
left join biz_message_read r on m.message_id = r.message_id and r.user_id = #{userId}
where m.status = '0'
  and r.read_id is null

      and m.message_type = #{messageType}

order by m.message_id desc
limit #{limitCount}

select count(1)
from biz_message m
left join biz_message_read r on m.message_id = r.message_id and r.user_id = #{userId}
where m.status = '0'
  and r.read_id is null

      and m.message_type = #{messageType}

select m.message_id, m.message_type, m.message_title, m.message_content, m.message_level, m.business_type, m.business_id, m.status, m.create_by, m.create_time, m.update_by, m.update_time, m.remark, '0' as read_status from biz_message m left join biz_message_read r on m.message_id = r.message_id and r.user_id = #{userId} where m.status = '0' and r.read_id is null
and m.message_type = #{messageType}
order by m.message_id desc

select message_id, message_type, message_title
from biz_message
where status = '0'
  and message_type = #{messageType}
  and message_title = #{messageTitle}
limit 1

select count(1)
from biz_message_read
where message_id = #{messageId}
  and user_id = #{userId}
